PRAGMA foreign_keys = ON;
CREATE TABLE IF NOT EXISTS roles (role_id TEXT PRIMARY KEY, role_name TEXT NOT NULL UNIQUE, description TEXT);
CREATE TABLE IF NOT EXISTS users (user_id TEXT PRIMARY KEY, display_name TEXT NOT NULL, email TEXT UNIQUE, department TEXT, position TEXT, role_id TEXT, is_active INTEGER DEFAULT 1 CHECK(is_active IN (0,1)), created_at TEXT DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY(role_id) REFERENCES roles(role_id));
CREATE TABLE IF NOT EXISTS suppliers (supplier_id TEXT PRIMARY KEY, supplier_name TEXT NOT NULL, material_type TEXT, risk_level TEXT CHECK(risk_level IN ('LOW','MEDIUM','HIGH','CRITICAL') OR risk_level IS NULL), coa_required INTEGER DEFAULT 0, halal_cert TEXT, gmp_status TEXT, approved_status TEXT CHECK(approved_status IN ('APPROVED','CONDITIONAL','SUSPENDED','REJECTED','PENDING') OR approved_status IS NULL), last_audit_date TEXT, material_code TEXT, source_sheet TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT);
CREATE TABLE IF NOT EXISTS materials (material_code TEXT PRIMARY KEY, material_name TEXT NOT NULL, material_type TEXT NOT NULL CHECK(material_type IN ('RM','DM','PM','CM','WIP','OTHER')), category TEXT, unit TEXT, min_temp_c REAL, max_temp_c REAL, storage_temp TEXT, shelf_life_days INTEGER, risk_level TEXT CHECK(risk_level IN ('LOW','MEDIUM','HIGH','CRITICAL') OR risk_level IS NULL), supplier_id TEXT, allergen_status TEXT CHECK(allergen_status IN ('CONTAINS','MAY_CONTAIN','FREE','UNKNOWN') OR allergen_status IS NULL), coa_required INTEGER DEFAULT 0, status TEXT DEFAULT 'ACTIVE', source_sheet TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT, FOREIGN KEY(supplier_id) REFERENCES suppliers(supplier_id));
CREATE TABLE IF NOT EXISTS finished_goods (fg_code TEXT PRIMARY KEY, fg_name TEXT NOT NULL, product_type TEXT, storage_temp_c REAL, shelf_life_days INTEGER, min_weight_g REAL, max_weight_g REAL, min_weight_pack_g REAL, max_weight_pack_g REAL, allergen_declaration TEXT, status TEXT DEFAULT 'ACTIVE', source_sheet TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT);
CREATE TABLE IF NOT EXISTS processes (process_id TEXT PRIMARY KEY, process_name TEXT NOT NULL, description TEXT, work_area TEXT, process_sequence INTEGER, source_sheet TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT);
CREATE TABLE IF NOT EXISTS parameters (parameter_id TEXT PRIMARY KEY, parameter_name TEXT NOT NULL, parameter_description TEXT, parameter_category TEXT, spec_limit TEXT, unit TEXT, source_sheet TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT);
CREATE TABLE IF NOT EXISTS equipment (equipment_id TEXT PRIMARY KEY, equipment_name TEXT NOT NULL, equipment_type TEXT, measurement_use TEXT, calibration_required INTEGER DEFAULT 1, calibration_due_date TEXT, status TEXT DEFAULT 'ACTIVE', source_sheet TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT);
CREATE TABLE IF NOT EXISTS machines (machine_id TEXT PRIMARY KEY, machine_name TEXT NOT NULL, process_id TEXT, machine_type TEXT, status TEXT DEFAULT 'ACTIVE', source_sheet TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT, FOREIGN KEY(process_id) REFERENCES processes(process_id));
CREATE TABLE IF NOT EXISTS ccp_master (ccp_id TEXT PRIMARY KEY, process_id TEXT NOT NULL, ccp_name TEXT NOT NULL, critical_limit TEXT NOT NULL, hazard_type TEXT CHECK(hazard_type IN ('BIOLOGICAL','CHEMICAL','PHYSICAL','ALLERGEN') OR hazard_type IS NULL), monitoring_frequency TEXT, corrective_action_standard TEXT, verification_method TEXT, source_sheet TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT, FOREIGN KEY(process_id) REFERENCES processes(process_id));
CREATE TABLE IF NOT EXISTS process_parameter_map (map_id INTEGER PRIMARY KEY AUTOINCREMENT, process_id TEXT NOT NULL, parameter_id TEXT NOT NULL, equipment_id TEXT, ccp_id TEXT, required INTEGER DEFAULT 1, source_sheet TEXT, UNIQUE(process_id, parameter_id, equipment_id, ccp_id), FOREIGN KEY(process_id) REFERENCES processes(process_id), FOREIGN KEY(parameter_id) REFERENCES parameters(parameter_id), FOREIGN KEY(equipment_id) REFERENCES equipment(equipment_id), FOREIGN KEY(ccp_id) REFERENCES ccp_master(ccp_id));
CREATE TABLE IF NOT EXISTS receiving_records (receiving_id TEXT PRIMARY KEY, receive_date TEXT NOT NULL, supplier_id TEXT NOT NULL, material_code TEXT NOT NULL, material_lot_no TEXT NOT NULL, po_no TEXT, do_no TEXT, quantity REAL, unit TEXT, vehicle_temp_c REAL, product_temp_c REAL, coa_result TEXT, visual_result TEXT, final_result TEXT DEFAULT 'PENDING' CHECK(final_result IN ('PASS','HOLD','REJECT','CONDITIONAL_ACCEPT','PENDING')), inspector_user_id TEXT, remark TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT, FOREIGN KEY(supplier_id) REFERENCES suppliers(supplier_id), FOREIGN KEY(material_code) REFERENCES materials(material_code));
CREATE TABLE IF NOT EXISTS production_batches (batch_id TEXT PRIMARY KEY, fg_code TEXT NOT NULL, production_date TEXT NOT NULL, line_no TEXT, formula_code TEXT, planned_qty REAL, actual_qty REAL, unit TEXT, supervisor_user_id TEXT, batch_status TEXT DEFAULT 'IN_PROCESS', created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT, FOREIGN KEY(fg_code) REFERENCES finished_goods(fg_code));
CREATE TABLE IF NOT EXISTS batch_material_usage (usage_id TEXT PRIMARY KEY, batch_id TEXT NOT NULL, material_code TEXT NOT NULL, material_lot_no TEXT NOT NULL, supplier_id TEXT, quantity_used REAL, unit TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY(batch_id) REFERENCES production_batches(batch_id), FOREIGN KEY(material_code) REFERENCES materials(material_code), FOREIGN KEY(supplier_id) REFERENCES suppliers(supplier_id));
CREATE TABLE IF NOT EXISTS finished_goods_lots (fg_lot_no TEXT PRIMARY KEY, batch_id TEXT NOT NULL, fg_code TEXT NOT NULL, production_date TEXT NOT NULL, expiry_date TEXT, quantity REAL, unit TEXT, release_status TEXT DEFAULT 'HOLD' CHECK(release_status IN ('HOLD','BLOCKED','RELEASED','REJECTED','DISPOSED')), qa_release_by TEXT, release_date TEXT, release_remark TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT, FOREIGN KEY(batch_id) REFERENCES production_batches(batch_id), FOREIGN KEY(fg_code) REFERENCES finished_goods(fg_code));
CREATE TABLE IF NOT EXISTS inspection_logs (inspection_id TEXT PRIMARY KEY, timestamp TEXT DEFAULT CURRENT_TIMESTAMP, inspector_user_id TEXT, process_id TEXT, equipment_id TEXT, fg_code TEXT, fg_lot_no TEXT, material_code TEXT, material_lot_no TEXT, parameter_id TEXT, value REAL, value_text TEXT, spec_min REAL, spec_max REAL, unit TEXT, result TEXT NOT NULL CHECK(result IN ('PASS','FAIL','HOLD','REJECT','PENDING','NA')), corrective_action TEXT, remark TEXT, attachment_url TEXT, related_ncr_id TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS water_test_logs (water_test_id TEXT PRIMARY KEY, timestamp TEXT DEFAULT CURRENT_TIMESTAMP, location TEXT NOT NULL, parameter_id TEXT, parameter_name TEXT, value REAL, spec_min REAL, spec_max REAL, unit TEXT, result TEXT NOT NULL CHECK(result IN ('PASS','FAIL','HOLD','PENDING','NA')), inspector_user_id TEXT, remark TEXT, related_ncr_id TEXT);
CREATE TABLE IF NOT EXISTS allergen_logs (allergen_log_id TEXT PRIMARY KEY, timestamp TEXT DEFAULT CURRENT_TIMESTAMP, area TEXT, fg_code TEXT, product_name TEXT, allergen TEXT NOT NULL, control_method TEXT, cleaning_verified INTEGER, verification_method TEXT, result TEXT NOT NULL CHECK(result IN ('PASS','FAIL','HOLD','PENDING','NA')), inspector_user_id TEXT, remark TEXT, related_ncr_id TEXT);
CREATE TABLE IF NOT EXISTS ccp_monitoring_logs (ccp_log_id TEXT PRIMARY KEY, timestamp TEXT DEFAULT CURRENT_TIMESTAMP, ccp_id TEXT NOT NULL, process_id TEXT, batch_id TEXT, fg_lot_no TEXT, parameter_id TEXT, critical_limit TEXT NOT NULL, actual_value TEXT, result TEXT NOT NULL CHECK(result IN ('PASS','FAIL','HOLD','PENDING')), corrective_action TEXT, verified_by TEXT, related_ncr_id TEXT, FOREIGN KEY(ccp_id) REFERENCES ccp_master(ccp_id));
CREATE TABLE IF NOT EXISTS metal_detector_logs (metal_log_id TEXT PRIMARY KEY, timestamp TEXT DEFAULT CURRENT_TIMESTAMP, line_no TEXT, ccp_id TEXT, fg_code TEXT, product_name TEXT, fg_lot_no TEXT, fe_test TEXT, nonfe_test TEXT, sus_test TEXT, detected_metal_type TEXT CHECK(detected_metal_type IN ('FE','NON_FE','SUS','UNKNOWN','NONE') OR detected_metal_type IS NULL), detected_size_mm REAL, critical_limit_mm REAL, result TEXT NOT NULL CHECK(result IN ('PASS','FAIL','HOLD','PENDING')), last_good_check_time TEXT, re_pass_count INTEGER DEFAULT 0, inspector_user_id TEXT, remark TEXT, related_ncr_id TEXT);
CREATE TABLE IF NOT EXISTS deviation_logs (deviation_id TEXT PRIMARY KEY, timestamp TEXT DEFAULT CURRENT_TIMESTAMP, process_id TEXT, equipment_id TEXT, parameter_id TEXT, value TEXT, spec TEXT, deviation_type TEXT, root_cause TEXT, immediate_action TEXT, responsible_user_id TEXT, status TEXT DEFAULT 'OPEN', risk_level TEXT CHECK(risk_level IN ('LOW','MEDIUM','HIGH','CRITICAL') OR risk_level IS NULL), ncr_required INTEGER DEFAULT 0, related_ncr_id TEXT);
CREATE TABLE IF NOT EXISTS ncr_records (ncr_id TEXT PRIMARY KEY, source_module TEXT, source_record_id TEXT, issue_date TEXT, lot_no TEXT, found_date TEXT, found_time TEXT, reported_by TEXT, process_id TEXT, process_ref TEXT, material_code TEXT, material_name TEXT, fg_code TEXT, supplier_id TEXT, supplier_name TEXT, parameter_id TEXT, parameter_name TEXT, critical_limit TEXT, actual_result TEXT, visual_check TEXT, nc_description TEXT NOT NULL, immediate_action TEXT, defect_qty REAL, defect_unit TEXT, root_cause TEXT, corrective_action TEXT, preventive_action TEXT, assignee TEXT, target_date TEXT, reply_date TEXT, verification_result TEXT, verification_note TEXT, risk_level TEXT CHECK(risk_level IN ('LOW','MEDIUM','HIGH','CRITICAL') OR risk_level IS NULL), product_status TEXT DEFAULT 'HOLD', disposition TEXT, status TEXT DEFAULT 'OPEN', closed_date TEXT, days_open INTEGER, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT);
CREATE TABLE IF NOT EXISTS capa_records (capa_id TEXT PRIMARY KEY, date_open TEXT NOT NULL, source TEXT, related_deviation_id TEXT, related_ncr_id TEXT, related_complaint_id TEXT, root_cause TEXT, corrective_action TEXT NOT NULL, preventive_action TEXT, owner TEXT, target_date TEXT, status TEXT DEFAULT 'OPEN', verification TEXT, verification_date TEXT, verified_by TEXT, effectiveness_result TEXT, close_date TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT);
CREATE TABLE IF NOT EXISTS customer_complaints (complaint_id TEXT PRIMARY KEY, complaint_date TEXT, received_by TEXT, department TEXT, position TEXT, customer_name TEXT, customer_phone TEXT, customer_email TEXT, channel TEXT, purchase_date TEXT, product_name TEXT, fg_code TEXT, fg_lot_no TEXT, quantity_issue REAL, issue_type TEXT, description TEXT, image_link TEXT, severity_level TEXT CHECK(severity_level IN ('LOW','MEDIUM','HIGH','CRITICAL') OR severity_level IS NULL), food_safety_risk INTEGER DEFAULT 0, recall_assessment_required INTEGER DEFAULT 0, investigation_result TEXT, root_cause TEXT, corrective_action TEXT, preventive_action TEXT, responsible_person TEXT, related_ncr_id TEXT, related_capa_id TEXT, qa_disposition TEXT, customer_reply_date TEXT, status TEXT DEFAULT 'OPEN', close_date TEXT, source_sheet TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT);
CREATE TABLE IF NOT EXISTS supplier_scorecards (scorecard_id TEXT PRIMARY KEY, supplier_id TEXT NOT NULL, review_date TEXT, delivery_ontime_pct REAL, quality_rejection_pct REAL, audit_score REAL, risk_level TEXT, overall_rating TEXT, reviewer TEXT, remark TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY(supplier_id) REFERENCES suppliers(supplier_id));
CREATE TABLE IF NOT EXISTS documents (document_id TEXT PRIMARY KEY, document_no TEXT NOT NULL UNIQUE, category TEXT, document_name TEXT NOT NULL, revision TEXT, effective_date TEXT, next_review_date TEXT, system TEXT, owner TEXT, department TEXT, location TEXT, status TEXT DEFAULT 'ACTIVE', file_link TEXT, keyword TEXT, remark TEXT, source_sheet TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT);
CREATE TABLE IF NOT EXISTS document_revisions (revision_id TEXT PRIMARY KEY, document_id TEXT NOT NULL, revision TEXT NOT NULL, change_detail TEXT, effective_date TEXT, approved_by TEXT, approved_at TEXT, file_link TEXT, status TEXT DEFAULT 'ACTIVE', FOREIGN KEY(document_id) REFERENCES documents(document_id));
CREATE TABLE IF NOT EXISTS document_approval_logs (approval_id TEXT PRIMARY KEY, timestamp TEXT DEFAULT CURRENT_TIMESTAMP, request_id TEXT, document_id TEXT, document_no TEXT, requested_rev TEXT, requester_name TEXT, requester_email TEXT, approver_name TEXT, approver_email TEXT, draft_file_link TEXT, draft_file_id TEXT, reason TEXT, decision TEXT, decision_by TEXT, decision_time TEXT, comment TEXT);
CREATE TABLE IF NOT EXISTS document_acknowledgement_logs (ack_id TEXT PRIMARY KEY, timestamp TEXT DEFAULT CURRENT_TIMESTAMP, employee_name TEXT, employee_email TEXT, department TEXT, document_id TEXT, document_no TEXT, revision TEXT, confirm TEXT, method TEXT, notes TEXT);
CREATE TABLE IF NOT EXISTS delivery_records (delivery_id TEXT PRIMARY KEY, delivery_date TEXT NOT NULL, customer_id TEXT, customer_name TEXT, fg_lot_no TEXT NOT NULL, quantity REAL, unit TEXT, vehicle_temp_c REAL, do_no TEXT, invoice_no TEXT, remark TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY(fg_lot_no) REFERENCES finished_goods_lots(fg_lot_no));
CREATE TABLE IF NOT EXISTS recall_records (recall_id TEXT PRIMARY KEY, recall_date TEXT DEFAULT CURRENT_TIMESTAMP, recall_type TEXT CHECK(recall_type IN ('MOCK','ACTUAL') OR recall_type IS NULL), fg_lot_no TEXT, reason TEXT, affected_quantity REAL, recovered_quantity REAL, recovery_pct REAL, customers_affected TEXT, recall_status TEXT DEFAULT 'OPEN', decision_by TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, closed_at TEXT);
CREATE TABLE IF NOT EXISTS mock_recall_records (mock_recall_id TEXT PRIMARY KEY, mock_date TEXT DEFAULT CURRENT_TIMESTAMP, fg_lot_no TEXT, rm_lot_no TEXT, start_time TEXT, end_time TEXT, time_used_min INTEGER, mass_balance_input_qty REAL, mass_balance_output_qty REAL, mass_balance_diff_qty REAL, mass_balance_diff_pct REAL, result TEXT, finding TEXT, action_required TEXT, conducted_by TEXT, approved_by TEXT);
CREATE TABLE IF NOT EXISTS attachments (attachment_id TEXT PRIMARY KEY, ref_table TEXT NOT NULL, ref_id TEXT NOT NULL, file_name TEXT, file_url TEXT NOT NULL, mime_type TEXT, uploaded_by TEXT, uploaded_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS alerts (alert_id TEXT PRIMARY KEY, alert_time TEXT DEFAULT CURRENT_TIMESTAMP, severity TEXT NOT NULL CHECK(severity IN ('INFO','WARNING','HIGH','CRITICAL')), module TEXT NOT NULL, ref_id TEXT, title TEXT NOT NULL, message TEXT, status TEXT DEFAULT 'OPEN', assigned_to TEXT, acknowledged_by TEXT, acknowledged_at TEXT, closed_at TEXT);
CREATE TABLE IF NOT EXISTS audit_logs (audit_id INTEGER PRIMARY KEY AUTOINCREMENT, event_time TEXT DEFAULT CURRENT_TIMESTAMP, user_id TEXT, action TEXT NOT NULL, entity_table TEXT NOT NULL, entity_id TEXT, old_value_json TEXT, new_value_json TEXT, ip_address TEXT, user_agent TEXT);
CREATE INDEX IF NOT EXISTS idx_materials_supplier ON materials(supplier_id);
CREATE INDEX IF NOT EXISTS idx_receiving_material_lot ON receiving_records(material_lot_no, material_code);
CREATE INDEX IF NOT EXISTS idx_batch_material_usage_lot ON batch_material_usage(material_lot_no, material_code);
CREATE INDEX IF NOT EXISTS idx_fg_lots_batch ON finished_goods_lots(batch_id, fg_code);
CREATE INDEX IF NOT EXISTS idx_inspection_lot ON inspection_logs(fg_lot_no, material_lot_no, result);
CREATE INDEX IF NOT EXISTS idx_ccp_logs_lot ON ccp_monitoring_logs(fg_lot_no, result);
CREATE INDEX IF NOT EXISTS idx_metal_logs_lot ON metal_detector_logs(fg_lot_no, result);
CREATE INDEX IF NOT EXISTS idx_ncr_lot_status ON ncr_records(lot_no, status, risk_level);
CREATE INDEX IF NOT EXISTS idx_capa_status_due ON capa_records(status, target_date);
CREATE INDEX IF NOT EXISTS idx_complaint_lot_status ON customer_complaints(fg_lot_no, status, severity_level);
CREATE INDEX IF NOT EXISTS idx_documents_status_review ON documents(status, next_review_date);
CREATE VIEW IF NOT EXISTS v_open_ncr AS SELECT ncr_id, issue_date, lot_no, nc_description, risk_level, product_status, status, assignee, target_date FROM ncr_records WHERE status NOT IN ('CLOSED','CANCELLED');
CREATE VIEW IF NOT EXISTS v_fg_release_blockers AS SELECT fg.fg_lot_no, fg.release_status, COUNT(DISTINCT n.ncr_id) AS open_ncr_count, COUNT(DISTINCT c.ccp_log_id) AS failed_ccp_count, COUNT(DISTINCT m.metal_log_id) AS failed_metal_count FROM finished_goods_lots fg LEFT JOIN ncr_records n ON n.lot_no=fg.fg_lot_no AND n.status NOT IN ('CLOSED','CANCELLED') LEFT JOIN ccp_monitoring_logs c ON c.fg_lot_no=fg.fg_lot_no AND c.result='FAIL' LEFT JOIN metal_detector_logs m ON m.fg_lot_no=fg.fg_lot_no AND m.result='FAIL' GROUP BY fg.fg_lot_no, fg.release_status;
CREATE VIEW IF NOT EXISTS v_traceability_fg AS SELECT fg.fg_lot_no, fg.fg_code, fgm.fg_name, fg.production_date, fg.expiry_date, fg.release_status, pb.batch_id, bmu.material_code, mat.material_name, bmu.material_lot_no, bmu.supplier_id, s.supplier_name, bmu.quantity_used, bmu.unit FROM finished_goods_lots fg JOIN finished_goods fgm ON fgm.fg_code=fg.fg_code JOIN production_batches pb ON pb.batch_id=fg.batch_id LEFT JOIN batch_material_usage bmu ON bmu.batch_id=pb.batch_id LEFT JOIN materials mat ON mat.material_code=bmu.material_code LEFT JOIN suppliers s ON s.supplier_id=bmu.supplier_id;
CREATE VIEW IF NOT EXISTS v_dashboard_kpi AS SELECT (SELECT COUNT(*) FROM receiving_records WHERE final_result='PASS') AS receiving_pass_count, (SELECT COUNT(*) FROM receiving_records WHERE final_result IN ('HOLD','REJECT')) AS receiving_hold_reject_count, (SELECT COUNT(*) FROM ncr_records WHERE status NOT IN ('CLOSED','CANCELLED')) AS open_ncr_count, (SELECT COUNT(*) FROM capa_records WHERE status IN ('OPEN','IN_PROGRESS','OVERDUE')) AS open_capa_count, (SELECT COUNT(*) FROM ccp_monitoring_logs WHERE result='FAIL') AS failed_ccp_count, (SELECT COUNT(*) FROM finished_goods_lots WHERE release_status IN ('HOLD','BLOCKED')) AS fg_hold_count, (SELECT COUNT(*) FROM customer_complaints WHERE status NOT IN ('CLOSED','CANCELLED')) AS open_complaint_count, (SELECT COUNT(*) FROM documents WHERE status='ACTIVE' AND next_review_date IS NOT NULL AND date(next_review_date) <= date('now','+30 day')) AS docs_due_review_30d;
CREATE VIEW IF NOT EXISTS v_documents_active AS SELECT * FROM documents WHERE status='ACTIVE';
-- Service-layer rules: Failed CCP/Metal must create NCR+alert and block FG release. Open NCR blocks release. Complaint HIGH/CRITICAL triggers recall assessment. Obsolete documents hidden from active forms.
